def InvalidBoard():
    # We deliberately look for an invalid board, because then the model
    # checker will try to find a counter-example. If it finds one, it will 
    # give us a valid solution.

    # First check if we have exactly N queens
    total_queens = 0
    for row in range(N):
        for col in range(N):
            if board[row][col] == 1:
                total_queens += 1
    if total_queens != N:
        return True  # Not all queens placed

    # Check 1: More than one queen in any row
    for row in range(N):
        queen_count = 0
        for col in range(N):
            if board[row][col] == 1:
                queen_count += 1
        if queen_count > 1:
            return True  # multiple queens in same row

    # Check 2: More than one queen in any column 
    for col in range(N):
        queen_count = 0
        for row in range(N):
            if board[row][col] == 1:
                queen_count += 1
        if queen_count > 1:
            return True  # multiple queens in same column

    # Check 3: Queens touching diagonally 
    for row in range(N):
        for col in range(N):
            if board[row][col] == 1:
                # Check all 4 diagonal neighbor positions explicitly
                # Upper-left diagonal
                if row > 0 and col > 0:
                    if board[row - 1][col - 1] == 1:
                        return True
                # Upper-right diagonal
                if row > 0 and col < N-1:
                    if board[row - 1][col + 1] == 1:
                        return True
                # Lower-left diagonal
                if row < N-1 and col > 0:
                    if board[row + 1][col - 1] == 1:
                        return True
                # Lower-right diagonal
                if row < N-1 and col < N-1:
                    if board[row + 1][col + 1] == 1:
                        return True

    # Check 4: Exactly one queen in each region
    for region_idx in range(N):
        queen_count = 0
        cells_in_region = REGIONS[region_idx]
        for cell in cells_in_region:
            row = (cell - 1) // N
            col = (cell - 1) % N
            if board[row][col] == 1:
                queen_count += 1
        if queen_count != 1:
            return True  # not exactly one queen in region

    #print("\n\n")
    #print("Solution grep")
    #for row in range(N):
    #    print(board[row])
    return False
